module binary_to_gray (
    input [3:0] inverse_binary,
    output [3:0] gray
);

    // Binary to Gray code conversion logic
    assign gray[3] = inverse_binary[3];
    assign gray[2] = inverse_binary[3] ^ inverse_binary[2];
    assign gray[1] = inverse_binary[2] ^ inverse_binary[1];
    assign gray[0] = inverse_binary[1] ^ inverse_binary[0];

endmodule
